var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어째…… 과거로 돌아온 기분이네요.","JPN":"何だか……過去に戻ってきたような気分ですね。","ENG":"Huh...? I feel like I've been transported into the past.","TWN":"怎麼……感覺回到了過去呢。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그렇지. 나도 직접 와 보는 건 처음이야. 꽤 목가적인 분위기로군.","JPN":"そうだな。私も直接来るのは初めてだ。なかなか牧歌的な雰囲気だ。","ENG":"I get what you mean. It's my first time visiting here as well. It seems quite peaceful here.","TWN":"是呀，我也是第一次來這裡。還蠻有鄉間風情的。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그보다 아무렇지 않나, 중사?","JPN":"それより、何ともないのか？　軍曹。","ENG":"Other than that, are you feeling all right, Sergeant?","TWN":"話說回來，你沒事吧，中士？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……뭐가 말이죠?","JPN":"……何がですか？","ENG":"...What do you mean?","TWN":"……你指什麼？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"자네 부탁을 받고 정부는 서둘러 외교적인 조치를 취했어.","JPN":"君の頼みで、政府は急いで外交的な措置を取った。","ENG":"The government acted diplomatically quickly after receiving your request.","TWN":"接收你的委託後，政府緊急採取了外交措施。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그러게요. 맛있는 빵가루라도 떨어지나 싶었겠죠.","JPN":"そうですね。何かおこぼれにでもありつけると思ったんでしょう。","ENG":"Yeah. Maybe they expected some tasty bread crumbs to fall on their lap?","TWN":"是啊。他們應該以為是天上掉下來的好事吧。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"한 사람이 나라를 움직인 셈이야. 조금은 어깨에 힘이 들어가지 않나.","JPN":"たった一人で国を動かしたようなものだ。少しは肩に力が入らないか？","ENG":"That means that you literally mobilized an entire country. Doesn't that mean anything to you?","TWN":"這相當於是你一個人改變了國家。你不覺得肩上的擔子有點重嗎。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"뭘 또……","JPN":"何をまた……","ENG":"Is it supposed to...?","TWN":"怎麼又……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"새 부리 가면 쓰고 다니는 괴짜들에게 휘둘리면서 나라 타령이라니 말이죠.","JPN":"ペストマスク被ってる変人たちに振り回されながら国の心配なんて。","ENG":"All they ever talk about is the state of the country while getting bullied by weirdos in bird masks.","TWN":"被一群帶著鳥嘴面具的怪胎牽著鼻子走，還說什麼為了國家。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이제 와서 새삼스럽지만, 침식 현상이 사라진 것도 결국 레버넌트 씨 덕분 아니에요?","JPN":"今更ですけど、侵食現象が消えたのも結局レヴナントさんのおかげじゃないんですか？","ENG":"This may seem abrupt, but isn't the Counterside Effect gone because of Revenant?","TWN":"雖然事到如今說這些有點刻意，但侵蝕現象消失最終也要歸功於亡靈不是嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"높으신 분들의 심오한 계획은 일단 차치하더라도요.","JPN":"お偉い方々の奥深い計画はとりあえずさておいてです。","ENG":"I mean, even if we disregard the agenda that the higher-ups have planned.","TWN":"哪怕先拋開高層們的深謀遠慮不談。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"마에스트로가 제대로 연주했으면 우린 다 멍멍 꿀꿀 신세였어요.","JPN":"マエストロがちゃんと演奏してたら、私たちはみんな獣も同然の状態になっていたんですよ。","ENG":"We'd all be going \\"woof, woof\\" and \\"oink oink\\" if Maestra performed properly.","TWN":"如果指揮家順利演奏，我們都會變成任人宰割的羔羊。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"자네는 처음 봤을 때보다 지금이 더 낫군.","JPN":"君は初めて会った時より今の方がいいな。","ENG":"I like you better now than when I first saw you.","TWN":"比起第一次遇見你的時候，現在的你看起來更好些。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그렇지. 개인적으로는, 자네 가족 일에 대해 사과를……","JPN":"そうだ。個人的には、君の家族のことについて謝罪を……","ENG":"Oh, that's right. I would like to personally give an apology about what happened to your family...","TWN":"是啊。我代表自己，想對你家的事說聲對不起……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아뇨. 사과하지 마세요.","JPN":"いいえ。謝らないでください。","ENG":"No. No apology is needed.","TWN":"不，你不用道歉。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그냥 앞으로도 쭉 나라를 위해 한 일이라고 우겨 주시라고요.","JPN":"ただこれからもずっと国のためのことだったって言い張ってくださいよ。","ENG":"Just keep telling them that I did it for my country.","TWN":"以後也請堅持說這是為了國家做的事。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"부모님도 그 편이 마음 편하실 테니까요.","JPN":"うちの両親もその方が気が楽でしょうから。","ENG":"My parents will like that way as well.","TWN":"那樣我的父母也會更安心。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이제 와서 국장님이 사과한다고 뭐가 달라지겠어요?","JPN":"今更局長が謝ったところで何も変わらないじゃないですか。","ENG":"Also, what difference will it make if you apologized now?","TWN":"事到如今，就算局長道歉又能改變什麼呢？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그래, 그렇겠지…….","JPN":"ああ、そうだろうな……","ENG":"Yeah... I guess you're right.","TWN":"是啊，應該是吧……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그런데 서로 어색한 사이인 저희는 여기서 언제까지 기다려야 하나요?","JPN":"それにしても、お互い気まずい間柄の私たちはいつまでここで待たなきゃならないんですか？","ENG":"It's kinda awkward just us two. How much longer do we have to wait here?","TWN":"不過話說回來，關係尷尬的我們，還要在這裡等到什麼時候啊？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"주민들 시선도 점점 조약돌 대하듯이 시들어가는데요.","JPN":"住民の視線も、段々石ころでも見るかのように冷めてきてるんですけど。","ENG":"Even the villagers don't seem to care about us anymore.","TWN":"居民們的目光也漸漸失去熱情了，看我們就像看路邊的石頭一樣。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"조금만 기다리게. 중요한 일이 있다니까……","JPN":"もう少しだけ待ってくれ。大事な用があるらしい……","ENG":"Just a little longer. We have important business here...","TWN":"再等等吧，說是有重要的事……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"죄송합니다. 감자 작황이 너무 좋은 나머지.","JPN":"申し訳ありません。ジャガイモの作柄があまりにもよかったので。","ENG":"Apologies for being late. Our potato harvest was so good that I lost track of time.","TWN":"抱歉我來晚了，因為馬鈴薯收成太好了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"기술교관 비비안 래시포드입니다.","JPN":"技術教官のビビアン・ラッシュフォードです。","ENG":"I am Vivian Rashford, the Technical Instructor here.","TWN":"我是技術教官薇薇安·雷希福特。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그로니아를 침식 현상에서 구원했다는 영웅 분이시죠. 소식을 듣고 꼭 뵙고 싶었습니다.","JPN":"グロニアを侵食現象から救ったという英雄の方ですね。話を聞いて、是非お会いしたいと思っていました。","ENG":"So you are the hero that saved Gronia from the Counterside Effect. I've been wanting to meet you ever since I heard the news.","TWN":"你就是在侵蝕現象中拯救了格羅尼亞的英雄吧。聽到消息後，我一直很想見你。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"크흠, 미안합니다. 제가 아니라……","JPN":"こほん、申し訳ないですが。私ではなくて……","ENG":"Ahem... I'm sorry, but it's not me, but...","TWN":"咳咳，抱歉，我不是……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……감자가 중대사인 부대라니 제대로 온 거 맞아요?","JPN":"……ジャガイモが重大事な部隊だなんて、ここで合ってるんですか？","ENG":"...A unit where potatoes are an important matter? Are you sure we're at the right place?","TWN":"……把收馬鈴薯當成重大事件的部隊，我來這裡真的沒錯嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};